import{_ as e,o as t,c as r,a2 as p}from"./chunks/framework.Crpw6aS5.js";const h=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/1968年/年中信.md","filePath":"01_letters/1968年/年中信.md"}'),o={name:"01_letters/1968年/年中信.md"};function s(n,a,_,l,i,c){return t(),r("div",null,[...a[0]||(a[0]=[p('<h2 id="_1968年7月11日-上半年业绩" tabindex="-1">1968年7月11日 上半年业绩 <a class="header-anchor" href="#_1968年7月11日-上半年业绩" aria-label="Permalink to &quot;1968年7月11日 上半年业绩&quot;">​</a></h2><p>1968年上半年，道指从905点微跌至898点，叠加股息收益，整体回报率0.9%。道指再次跑输多数投资机构，但差距较1967年缩小。</p><p>我们上半年表现优异，不含控股企业估值变动，整体收益16%（年初控股企业占净资产超三分之一）。但无需过度兴奋，我们的证券投资高度集中，业绩波动大于分散型投资。长期目标仍按修订后“基本规则”执行，能多年实现温和目标我就很满意。</p><p><strong>业绩汇总</strong>：</p><p>1957-1968年上半年，道指累计收益167.7%，年均复合8.9%；合伙公司累计1880.0%，年均复合29.6%；有限合伙人累计1072.0%，年均复合23.8%。</p><p>控股企业1968年盈利预计超300万美元，伯克希尔、多元零售、国民赔偿、联合棉花商店的管理层均表现出色。多元零售公司因发行债券成为公众债权人视角的上市公司，实际仍由BPL控股80%。</p><p>长期持有控股企业的收益，低于买卖企业或投资流通证券，但与优秀人才合作、稳健运营，是令人愉悦的长期选择。</p><h3 id="市场环境" tabindex="-1">市场环境 <a class="header-anchor" href="#市场环境" aria-label="Permalink to &quot;市场环境&quot;">​</a></h3><p>我从不预测宏观经济与股市走势。但当前金融市场的 practices 快速蔓延，短期无预测意义，长期隐患令我担忧。</p><p>市场正盛行连锁信式的股票炒作，发起人、高管、顾问、投行、投机者等赚得盆满钵满，参与者多是轻信、自我催眠或投机取巧之人。为制造假象，他们频繁使用会计操纵、资本结构把戏、掩盖业务实质等手段。这种模式看似体面、流行、暴利，实则是一场狂热。</p><p>坦率地说，我们的业绩间接受益于这种热潮——炒作需要大量企业标的，让我们持有的低价股快速兑现价值。但这种狂热也让优质投资标的愈发稀缺。</p><p>我相信，多年后回顾这段历史，这场炒作会被定义为重要的市场狂热。当下多数投行与成功投资者对此不以为然，但市场由充满希望、轻信、贪婪的人主导，他们只需要一个相信的理由。</p><p>最后，强烈推荐亚当·史密斯的《金钱游戏》，充满洞见与幽默，售价6.95美元。</p><h3 id="税务" tabindex="-1">税务 <a class="header-anchor" href="#税务" aria-label="Permalink to &quot;税务&quot;">​</a></h3><p>今年税务预估难度更大，普通收入高于往年，长短期资本利得波动极大。年初我建议按BPL资本金的8%估算普通收入，用于季度预缴。若9月15日预缴需调整比例，我会在9月5日前告知；若无调整，下次联系是11月1日的1969年承诺函。</p><p>此致</p><p>沃伦·E·巴菲特</p><hr><h2 id="_1969年1月22日-信件开篇" tabindex="-1">1969年1月22日 （信件开篇） <a class="header-anchor" href="#_1969年1月22日-信件开篇" aria-label="Permalink to &quot;1969年1月22日 （信件开篇）&quot;">​</a></h2><p>（注：原文此处仅标注日期，无后续内容）</p><p>要不要我把这份翻译<strong>整理成可直接打印的纯文本版本</strong>，方便你阅读和保存？</p><blockquote><p>（注：文档部分内容可能由 AI 生成）</p></blockquote>',22)])])}const u=e(o,[["render",s]]);export{h as __pageData,u as default};
